function answer(question):
    messages = [system_prompt, user(question)]
    for step in 1..MAX_STEPS:
        reply = llm.generate(
            messages=messages,
            tools=[retrieve_vector, retrieve_graph, retrieve_web],
        )
        messages.append(reply)

        if not reply.tool_calls:
            return reply.content              # agent answered

        for call in reply.tool_calls:
            evidence = dispatch(call.name, call.args)
            messages.append(tool_result(call.id, evidence))
        # next iteration: agent sees evidence and either answers,
        # reformulates the query, or picks a different retriever.

    return abort("step budget exhausted")     # bounded by MAX_STEPS

function answer_with_citations(question):
    chunks   = retrieve(question, k=10)
    registry = { c.id: c for c in chunks }                # stable ids for this turn

    prompt = render(
        question = question,
        sources  = [(c.id, c.text) for c in chunks],
        schema   = { claims: [ { text, supporting_chunk_ids: [str] } ] },
    )
    draft = llm.generate(prompt, response_format="json_schema")

    # validate: every cited id must have been retrieved this turn
    for claim in draft.claims:
        claim.supporting_chunk_ids = [
            sid for sid in claim.supporting_chunk_ids if sid in registry
        ]
        if not claim.supporting_chunk_ids:
            claim.warning = "unsupported_claim"

    return {
        "claims":  draft.claims,
        "sources": [registry[sid] for sid in cited_ids(draft)],
    }

function crag(query):
    docs   = retrieve(query, k=5)
    graded = [(d, evaluator.grade(query, d)) for d in docs]
        # grade in {Correct, Ambiguous, Incorrect}

    keep      = [d for d, g in graded if g == "Correct"]
    ambiguous = [d for d, g in graded if g == "Ambiguous"]
    bad       = [d for d, g in graded if g == "Incorrect"]

    if ambiguous or bad:
        rewritten = llm.rewrite(query)
        web_docs  = web_search(rewritten, k=5)
    else:
        web_docs = []

    final_docs = keep + ambiguous + web_docs              # drop `bad`
    return llm.generate(question=query, context=final_docs)

from llama_index.core.workflow import (
    Workflow, step, Context, StartEvent, StopEvent, Event,
)
from llama_index.core import VectorStoreIndex, SummaryIndex, Document
from llama_index.llms.openai import OpenAI
from llama_index.tools.tavily_research.base import TavilyToolSpec

llm = OpenAI(model="gpt-4o-mini")

RELEVANCE_PROMPT = (
    "Given the query: {query}\nAnd the document: {doc}\n"
    "Is this document relevant? Answer 'yes' or 'no'."
)


class RetrievedEvent(Event):
    nodes: list


class CorrectiveRAGWorkflow(Workflow):
    @step
    async def retrieve(self, ev: StartEvent) -> RetrievedEvent:
        index: VectorStoreIndex = ev.index
        nodes = index.as_retriever(similarity_top_k=5).retrieve(ev.query)
        return RetrievedEvent(nodes=nodes)

    @step
    async def grade_and_answer(
        self, ctx: Context, ev: RetrievedEvent
    ) -> StopEvent:
        query = await ctx.get("query")
        grades = [
            llm.complete(
                RELEVANCE_PROMPT.format(query=query, doc=n.get_content())
            ).text.strip().lower()
            for n in ev.nodes
        ]
        relevant = [n for n, g in zip(ev.nodes, grades) if g.startswith("yes")]
        if any(g.startswith("no") for g in grades):
            tavily = TavilyToolSpec(api_key="YOUR_TAVILY_KEY")
            web_docs = tavily.search(query, max_results=5)
            relevant += [Document(text=d.text) for d in web_docs]
        answer = SummaryIndex.from_documents(
            [Document(text=n.get_content()) for n in relevant]
        ).as_query_engine(llm=llm).query(query)
        return StopEvent(result=str(answer))

function index(docs):
    triples = []
    for chunk in flat_map(split, docs):
        triples += llm.extract_entities_and_relations(chunk)
    graph        = build_graph(triples)
    communities  = hierarchical_cluster(graph)            # Leiden / similar
    summaries    = { c.id: llm.summarise(c.nodes) for c in communities }
    return graph, summaries

function query(q, graph, summaries):
    kind = llm.classify(q, ["local", "global"])
    if kind == "local":
        seeds = match_entities(q, graph)
        ctx   = graph.neighbourhood(seeds, depth=2)
        return llm.generate(question=q, context=ctx)
    else:                                                 # global
        partials = [llm.answer(q, s) for s in summaries.values()]  # map
        return llm.reduce(q, partials)                              # reduce

function hybrid_search(query, k=10):
    bm25_hits  = bm25_index.search(query, k=k)
    dense_hits = vector_index.search(embed(query), k=k)

    # Reciprocal Rank Fusion — rank-based, scale-free
    scores = {}
    C = 60                                                # standard RRF constant
    for rank, doc in enumerate(bm25_hits):
        scores[doc.id] = scores.get(doc.id, 0) + 1 / (C + rank)
    for rank, doc in enumerate(dense_hits):
        scores[doc.id] = scores.get(doc.id, 0) + 1 / (C + rank)

    fused = sort_desc(scores.items(), by=value)
    return [docs[doc_id] for doc_id, _ in fused[:k]]

